module RefModule (
    input wire [1:0] in,
    output wire [3:0] out
);

    wire __out_tmp = (in == 2'b00) ? 4'b0001 :
                 (in == 2'b01) ? 4'b0010 :
                 (in == 2'b10) ? 4'b0100 :
                 (in == 2'b11) ? 4'b1000 : 4'b0000;
    assign out = __out_tmp;

endmodule
